/*
** GLR (Generalized LR) parser support for Lime.
**
** This module implements a Graph-Structured Stack (GSS) and the GLR
** parsing algorithm on top of the LALR(1) tables generated by Lime.
** When a shift/reduce or reduce/reduce conflict is encountered at
** runtime, the parser forks into multiple parallel stack heads rather
** than reporting an error. Heads that converge to the same state are
** merged, optionally using a user-provided disambiguation callback.
**
** The feed function takes a ParserSnapshot rather than the original
** 19 individual table pointers and constants.  This keeps the GLR
** path symmetric with the LALR runtime in src/parse_engine.c, which
** also drives the snapshot directly.  All the dispatch constants
** (yy_min_shiftreduce, yy_max_shiftreduce, yy_min_reduce,
** yy_accept_action, yy_error_action, yy_no_action) live on the
** snapshot already; passing them individually was redundant and
** error-prone.
*/

#include "glr.h"
#include "snapshot.h"
#include "lime_ast.h"

#include <stdlib.h>
#include <string.h>

#define GLR_INITIAL_HEADS 16
#define GLR_INITIAL_PREDS 4
#define GLR_DEFAULT_ARENA (64 * 1024)

/* ------------------------------------------------------------------ */
/* GSSNode operations                                                  */
/* ------------------------------------------------------------------ */

GSSNode *gss_node_create(LimeArena *arena, uint32_t state) {
    GSSNode *node = (GSSNode *)lime_arena_calloc(arena, sizeof(GSSNode));
    if (!node) return NULL;
    node->state = state;
    node->refcount = 1;
    node->npred = 0;
    node->pred_capacity = 0;
    node->predecessors = NULL;
    return node;
}

void gss_node_add_predecessor(GSSNode *node, GSSNode *pred) {
    if (!node || !pred) return;

    /* Grow predecessors array if needed */
    if (node->npred >= node->pred_capacity) {
        uint32_t new_cap = node->pred_capacity == 0 ? GLR_INITIAL_PREDS : node->pred_capacity * 2;
        GSSNode **new_preds = (GSSNode **)realloc(node->predecessors, new_cap * sizeof(GSSNode *));
        if (!new_preds) return; /* allocation failure - silently drop */
        node->predecessors = new_preds;
        node->pred_capacity = new_cap;
    }

    node->predecessors[node->npred++] = pred;
    gss_node_acquire(pred);
}

GSSNode *gss_node_acquire(GSSNode *node) {
    if (node) node->refcount++;
    return node;
}

void gss_node_release(GSSNode *node) {
    if (!node) return;
    if (node->refcount > 0) node->refcount--;
    /* Note: actual deallocation is handled by the arena.
    ** The refcount is used to track logical liveness for
    ** predecessor cleanup. We free the predecessors array
    ** (which is heap-allocated) when refcount reaches zero. */
    if (node->refcount == 0 && node->predecessors) {
        /* Release all predecessors recursively */
        for (uint32_t i = 0; i < node->npred; i++) {
            gss_node_release(node->predecessors[i]);
        }
        free(node->predecessors);
        node->predecessors = NULL;
        node->npred = 0;
        node->pred_capacity = 0;
    }
}

/* ------------------------------------------------------------------ */
/* GLRParser lifecycle                                                  */
/* ------------------------------------------------------------------ */

GLRParser *glr_parser_create(uint32_t initial_state, size_t arena_size) {
    GLRParser *parser = (GLRParser *)calloc(1, sizeof(GLRParser));
    if (!parser) return NULL;

    if (arena_size == 0) arena_size = GLR_DEFAULT_ARENA;
    parser->arena = lime_arena_create(arena_size);
    if (!parser->arena) {
        free(parser);
        return NULL;
    }

    parser->max_heads = GLR_INITIAL_HEADS;
    parser->active_heads = (GSSNode **)calloc(parser->max_heads, sizeof(GSSNode *));
    if (!parser->active_heads) {
        lime_arena_destroy(parser->arena);
        free(parser);
        return NULL;
    }

    /* Create the initial GSS node at the start state */
    GSSNode *start = gss_node_create(parser->arena, initial_state);
    if (!start) {
        free(parser->active_heads);
        lime_arena_destroy(parser->arena);
        free(parser);
        return NULL;
    }
    parser->active_heads[0] = start;
    parser->nheads = 1;
    parser->total_forks = 0;
    parser->total_merges = 0;
    parser->has_ambiguity = false;

    return parser;
}

void glr_parser_destroy(GLRParser *parser) {
    if (!parser) return;

    /* Release all active head references */
    for (uint32_t i = 0; i < parser->nheads; i++) {
        gss_node_release(parser->active_heads[i]);
    }
    free(parser->active_heads);

    /* Arena destroys all GSSNode storage in bulk */
    lime_arena_destroy(parser->arena);
    free(parser);
}

/* ------------------------------------------------------------------ */
/* Internal helpers                                                     */
/* ------------------------------------------------------------------ */

/*
** Look up the shift action for a terminal token in a given state.
** Mirrors the yy_find_shift_action logic in limpar.c, operating on
** the snapshot's table arrays.
*/
static uint16_t glr_find_shift_action(const ParserSnapshot *snap, uint32_t stateno,
                                      uint16_t token) {
    if (stateno >= snap->nstate) return snap->yy_default[stateno];
    int32_t ofst = snap->yy_shift_ofst[stateno];
    int32_t idx = ofst + (int32_t)token;
    if (idx >= 0 && (uint32_t)idx < snap->lookahead_count &&
        snap->yy_lookahead[idx] == token) {
        return snap->yy_action[idx];
    }
    return snap->yy_default[stateno];
}

/*
** Look up the reduce (goto) action for a nonterminal after reduction.
** Mirrors yy_find_reduce_action in limpar.c.
*/
static uint16_t glr_find_reduce_action(const ParserSnapshot *snap, uint32_t stateno,
                                       uint16_t nonterminal) {
    int32_t ofst = snap->yy_reduce_ofst[stateno];
    int32_t idx = ofst + (int32_t)nonterminal;
    if (idx >= 0 && (uint32_t)idx < snap->lookahead_count &&
        snap->yy_lookahead[idx] == nonterminal) {
        return snap->yy_action[idx];
    }
    return snap->yy_default[stateno];
}

/*
** Grow the active_heads array if it is full.
*/
static int glr_grow_heads(GLRParser *parser) {
    uint32_t new_cap = parser->max_heads * 2;
    GSSNode **new_arr = (GSSNode **)realloc(parser->active_heads, new_cap * sizeof(GSSNode *));
    if (!new_arr) return -1;
    parser->active_heads = new_arr;
    parser->max_heads = new_cap;
    return 0;
}

/*
** Add a new head to the active set. Returns 0 on success, -1 on failure.
*/
static int glr_add_head(GLRParser *parser, GSSNode *node) {
    if (parser->nheads >= parser->max_heads) {
        if (glr_grow_heads(parser) != 0) return -1;
    }
    parser->active_heads[parser->nheads++] = gss_node_acquire(node);
    return 0;
}

/*
** Merge phase: after all heads have been processed for a token,
** merge any heads that have arrived at the same parser state.
** When two heads share a state, their predecessor lists are combined
** into a single node.  Without a disambiguation callback, the merge
** is recorded as an ambiguity.
*/
static int glr_merge_heads(GLRParser *parser) {
    for (uint32_t i = 0; i < parser->nheads; i++) {
        if (!parser->active_heads[i]) continue;
        for (uint32_t j = i + 1; j < parser->nheads; j++) {
            if (!parser->active_heads[j]) continue;
            if (parser->active_heads[i]->state == parser->active_heads[j]->state) {
                /* Merge j into i: add j's predecessors to i */
                GSSNode *survivor = parser->active_heads[i];
                GSSNode *merged = parser->active_heads[j];

                for (uint32_t k = 0; k < merged->npred; k++) {
                    gss_node_add_predecessor(survivor, merged->predecessors[k]);
                }

                /* If no disambiguation callback, mark ambiguity.  When
                ** a callback is present we trust it to have already
                ** chosen between competing reductions during the feed
                ** phase, so a state-level merge here is just stack
                ** sharing rather than a true ambiguity. */
                if (!parser->disambiguate) {
                    parser->has_ambiguity = true;
                }

                gss_node_release(merged);
                parser->active_heads[j] = NULL;
                parser->total_merges++;
            }
        }
    }

    /* Compact the heads array (remove NULLs) */
    uint32_t write = 0;
    for (uint32_t read = 0; read < parser->nheads; read++) {
        if (parser->active_heads[read]) {
            parser->active_heads[write++] = parser->active_heads[read];
        }
    }
    parser->nheads = write;

    return 0;
}

/* ------------------------------------------------------------------ */
/* Main feed function                                                  */
/* ------------------------------------------------------------------ */

/*
** Step a single head forward by one token.  Mirrors the dispatch loop
** in parse_engine.c -- the head is driven through any pending reduces
** until it either consumes the token (shift / shift-reduce) or dies
** (syntax error / reduce-fail).  The function appends 0 or 1 surviving
** heads to parser->active_heads for the next merge phase.
**
** Returns 0 if the step completed (shift/accept/dead), or sets *fork_action
** to the alternative reduce action when fork detection triggers (the
** caller is responsible for spawning the forked head before stepping
** the survivor).
*/
static void glr_step_one_head(GLRParser *parser, const ParserSnapshot *snap, GSSNode *head,
                              uint16_t token, uint16_t *fork_action) {
    const uint16_t min_shiftreduce = snap->yy_min_shiftreduce;
    const uint16_t max_shiftreduce = snap->yy_max_shiftreduce;
    const uint16_t min_reduce = snap->yy_min_reduce;
    const uint16_t max_shift = snap->yy_max_shift;
    const uint16_t error_action = snap->yy_error_action;
    const uint16_t accept_action = snap->yy_accept_action;
    const uint16_t no_action = snap->yy_no_action;
    const uint32_t nrule = snap->nrule;

    *fork_action = 0;
    GSSNode *cur = gss_node_acquire(head);

    /* Drive the head through any pending reduces, then consume the
    ** token (or die).  Cap the iteration count to avoid infinite
    ** loops on a malformed snapshot. */
    for (int safety = 0; safety < 256; safety++) {
        uint16_t state = (uint16_t)cur->state;

        /* Pending-reduce state: unpack and apply the reduce.  No
        ** token is consumed during this; we'll loop and re-look up
        ** an action against the new state. */
        if (state >= min_reduce) {
            uint32_t rule_no = state - min_reduce;
            if (rule_no >= nrule) { gss_node_release(cur); return; }
            int rhs_len = -(int)snap->yy_rule_info_nrhs[rule_no];
            uint16_t lhs = (uint16_t)snap->yy_rule_info_lhs[rule_no];

            GSSNode *base = cur;
            for (int step = 0; step < rhs_len && base && base->npred > 0; step++) {
                base = base->predecessors[0];
            }
            if (!base) { gss_node_release(cur); return; }

            uint16_t goto_action = glr_find_reduce_action(snap, base->state, lhs);
            if (goto_action == accept_action) {
                /* The reduce completed the start rule. */
                GSSNode *acc = gss_node_create(parser->arena, accept_action);
                if (acc) {
                    gss_node_add_predecessor(acc, base);
                    glr_add_head(parser, acc);
                    gss_node_release(acc);
                }
                gss_node_release(cur);
                return;
            }
            if (goto_action == error_action || goto_action == no_action) {
                gss_node_release(cur);
                return; /* head dies */
            }
            /* Re-encode shift-reduce in the goto slot as a pending reduce. */
            if (goto_action > max_shift && goto_action <= max_shiftreduce) {
                goto_action = (uint16_t)(goto_action + (min_reduce - min_shiftreduce));
            }
            GSSNode *next_head = gss_node_create(parser->arena, goto_action);
            if (!next_head) { gss_node_release(cur); return; }
            gss_node_add_predecessor(next_head, base);
            gss_node_release(cur);
            cur = next_head;
            continue;
        }

        /* Look up action for (state, token). */
        uint16_t action = glr_find_shift_action(snap, state, token);

        if (action == error_action || action == no_action) {
            gss_node_release(cur);
            return; /* head dies */
        }
        if (action == accept_action) {
            /* Accept: keep cur as a single accepted head. */
            GSSNode *acc = gss_node_create(parser->arena, accept_action);
            if (acc) {
                gss_node_add_predecessor(acc, cur);
                glr_add_head(parser, acc);
                gss_node_release(acc);
            }
            gss_node_release(cur);
            return;
        }

        if (action <= max_shift) {
            /* Simple shift -- token consumed. */
            GSSNode *shifted = gss_node_create(parser->arena, action);
            if (!shifted) { gss_node_release(cur); return; }
            gss_node_add_predecessor(shifted, cur);

            /* Fork detection: if yy_default is a different reduce
            ** action than the primary shift, the LALR generator
            ** silently resolved an S/R conflict here.  In GLR mode
            ** we want to also explore the reduce path. */
            uint16_t def_action = snap->yy_default[state];
            if (def_action >= min_reduce && def_action != action) {
                *fork_action = def_action;
            }

            glr_add_head(parser, shifted);
            gss_node_release(shifted);
            gss_node_release(cur);
            return;
        }

        if (action <= max_shiftreduce) {
            /* Shift-reduce: encode as pending reduce. */
            uint16_t encoded = (uint16_t)(action + (min_reduce - min_shiftreduce));
            GSSNode *shifted = gss_node_create(parser->arena, encoded);
            if (!shifted) { gss_node_release(cur); return; }
            gss_node_add_predecessor(shifted, cur);
            glr_add_head(parser, shifted);
            gss_node_release(shifted);
            gss_node_release(cur);
            return;
        }

        /* Pure reduce -- do not consume the token, loop. */
        if (action >= min_reduce) {
            uint32_t rule_no = action - min_reduce;
            if (rule_no >= nrule) { gss_node_release(cur); return; }
            int rhs_len = -(int)snap->yy_rule_info_nrhs[rule_no];
            uint16_t lhs = (uint16_t)snap->yy_rule_info_lhs[rule_no];

            GSSNode *base = cur;
            for (int step = 0; step < rhs_len && base && base->npred > 0; step++) {
                base = base->predecessors[0];
            }
            if (!base) { gss_node_release(cur); return; }

            uint16_t goto_action = glr_find_reduce_action(snap, base->state, lhs);
            if (goto_action == accept_action) {
                GSSNode *acc = gss_node_create(parser->arena, accept_action);
                if (acc) {
                    gss_node_add_predecessor(acc, base);
                    glr_add_head(parser, acc);
                    gss_node_release(acc);
                }
                gss_node_release(cur);
                return;
            }
            if (goto_action == error_action || goto_action == no_action) {
                gss_node_release(cur);
                return;
            }
            if (goto_action > max_shift && goto_action <= max_shiftreduce) {
                goto_action = (uint16_t)(goto_action + (min_reduce - min_shiftreduce));
            }
            GSSNode *next_head = gss_node_create(parser->arena, goto_action);
            if (!next_head) { gss_node_release(cur); return; }
            gss_node_add_predecessor(next_head, base);
            gss_node_release(cur);
            cur = next_head;
            continue;
        }

        /* Unknown action -- die. */
        gss_node_release(cur);
        return;
    }
    /* Safety cap reached: bail out without adding a head. */
    gss_node_release(cur);
}

/*
** Spawn a forked head whose first action is `forced_action`, then
** drive it forward.  Used when fork detection on the survivor's step
** produced an alternative reduce action that we want to also explore.
*/
static void glr_step_forked_head(GLRParser *parser, const ParserSnapshot *snap, GSSNode *head,
                                 uint16_t forced_action, uint16_t token) {
    const uint16_t min_reduce = snap->yy_min_reduce;
    const uint16_t max_shift = snap->yy_max_shift;
    const uint16_t max_shiftreduce = snap->yy_max_shiftreduce;
    const uint16_t min_shiftreduce = snap->yy_min_shiftreduce;
    const uint16_t accept_action = snap->yy_accept_action;
    const uint16_t error_action = snap->yy_error_action;
    const uint16_t no_action = snap->yy_no_action;
    const uint32_t nrule = snap->nrule;

    if (forced_action < min_reduce) return;
    uint32_t rule_no = forced_action - min_reduce;
    if (rule_no >= nrule) return;

    int rhs_len = -(int)snap->yy_rule_info_nrhs[rule_no];
    uint16_t lhs = (uint16_t)snap->yy_rule_info_lhs[rule_no];

    GSSNode *base = head;
    for (int step = 0; step < rhs_len && base && base->npred > 0; step++) {
        base = base->predecessors[0];
    }
    if (!base) return;

    uint16_t goto_action = glr_find_reduce_action(snap, base->state, lhs);
    if (goto_action == accept_action) {
        GSSNode *acc = gss_node_create(parser->arena, accept_action);
        if (acc) {
            gss_node_add_predecessor(acc, base);
            glr_add_head(parser, acc);
            gss_node_release(acc);
        }
        parser->total_forks++;
        return;
    }
    if (goto_action == error_action || goto_action == no_action) return;

    if (goto_action > max_shift && goto_action <= max_shiftreduce) {
        goto_action = (uint16_t)(goto_action + (min_reduce - min_shiftreduce));
    }
    GSSNode *forked = gss_node_create(parser->arena, goto_action);
    if (!forked) return;
    gss_node_add_predecessor(forked, base);

    /* Drive the forked head forward against the same token; the
    ** above goto only handles the reduce -- the token still needs
    ** to be processed. */
    uint16_t ignored_fork = 0;
    glr_step_one_head(parser, snap, forked, token, &ignored_fork);
    gss_node_release(forked);
    parser->total_forks++;
}

int glr_parser_feed(GLRParser *parser, const ParserSnapshot *snap, uint16_t token) {
    if (!parser || !snap || parser->nheads == 0) return -2;
    if (!snap->yy_action || !snap->yy_lookahead || !snap->yy_shift_ofst ||
        !snap->yy_reduce_ofst || !snap->yy_default || !snap->yy_rule_info_lhs ||
        !snap->yy_rule_info_nrhs) {
        return -2;
    }

    /* Snapshot the current head set; we rebuild parser->active_heads
    ** as we step each head forward. */
    uint32_t orig_nheads = parser->nheads;
    GSSNode **orig_heads = (GSSNode **)malloc(orig_nheads * sizeof(GSSNode *));
    if (!orig_heads) return -2;
    memcpy(orig_heads, parser->active_heads, orig_nheads * sizeof(GSSNode *));
    parser->nheads = 0;

    for (uint32_t h = 0; h < orig_nheads; h++) {
        GSSNode *head = orig_heads[h];
        uint16_t fork_action = 0;
        glr_step_one_head(parser, snap, head, token, &fork_action);
        if (fork_action != 0) {
            glr_step_forked_head(parser, snap, head, fork_action, token);
        }
        gss_node_release(head);
    }
    free(orig_heads);

    if (parser->nheads == 0) return -2;

    glr_merge_heads(parser);

    if (parser->has_ambiguity && !parser->disambiguate) return -1;
    return 0;
}

/* ------------------------------------------------------------------ */
/* Configuration and query                                             */
/* ------------------------------------------------------------------ */

void glr_parser_set_disambiguate(GLRParser *parser, GLRDisambiguateFn fn, void *user_data) {
    if (!parser) return;
    parser->disambiguate = fn;
    parser->disambiguate_data = user_data;
    /* Clear any prior ambiguity flag: with a callback installed the
    ** caller has signalled they will resolve merges, so previous
    ** unresolved-ambiguity status should not leak forward. */
    parser->has_ambiguity = false;
}

uint32_t glr_parser_head_count(const GLRParser *parser) {
    if (!parser) return 0;
    return parser->nheads;
}

bool glr_parser_accepted(const GLRParser *parser, uint16_t accept_action) {
    if (!parser) return false;
    /* Accept is indicated by exactly one head in the accept state */
    if (parser->nheads != 1) return false;
    return parser->active_heads[0]->state == accept_action;
}
